   374|export async function dispatchTask(task, options = {}) {
   375|  const config = await getConfig();
   376|  const platform = detectPlatform(task.assignee, config);
   377|
   378|  if (options.dryRun) {
   379|    return {
   380|      taskId: task.id,
   381|      assignee: task.assignee,
   382|      platform,
   383|      success: true,
   384|      status: null,
   385|      response: { dryRun: true, wouldDispatchTo: platform },
   386|      error: null,
   387|    };
   388|  }
   389|
   390|  switch (platform) {
   391|    case 'paperclip':
   392|      return dispatchToPaperclip(task);
   393|    case 'openclaw':
   394|      return dispatchToOpenClaw(task);
   395|    case 'hermes':
